import{_ as r,o,c as t,a3 as a}from"./chunks/framework.CjquFG0V.js";const f=JSON.parse('{"title":"47. Hours Of Work","description":"","frontmatter":{"title":"47. Hours Of Work","eba":"Allied Health Professionals 2021-2026","topics":["hours"]},"headers":[],"relativePath":"ebas/allied-health/hours-of-work/47-hours-of-work.md","filePath":"ebas/allied-health/hours-of-work/47-hours-of-work.md"}'),s={name:"ebas/allied-health/hours-of-work/47-hours-of-work.md"};function n(i,e,l,h,p,u){return o(),t("div",null,[...e[0]||(e[0]=[a('<h1 id="_47-hours-of-work" tabindex="-1">47. Hours Of Work <a class="header-anchor" href="#_47-hours-of-work" aria-label="Permalink to &quot;47. Hours Of Work&quot;">​</a></h1><p><strong>47.1</strong> The hours for an ordinary week’s work will be:</p><p><strong>(a)</strong> 38;</p><p><strong>(b)</strong> an average of 38 per week in a two (2) or four (4) week period; or</p><p><strong>(c)</strong> by mutual agreement, an average of 38 per week in a five (5) week period in the case of an Employee working ten hour shifts.</p><p><strong>47.2</strong> The hours for an ordinary week’s work will be worked either:</p><p><strong>(a)</strong> subject to <a href="/eba/ebas/allied-health/hours-of-work/48-accrued-days-off.html">clause 48</a> (Accrued Days Off), in 152 hours per four (4) week period worked as nineteen shifts each of eight (8) hours; or</p><p><strong>(b)</strong> by mutual agreement:</p><p><strong>(i)</strong> in four (4) days in shifts of not more than ten hours each; or</p><p><strong>(ii)</strong> otherwise, provided that the length of any ordinary shift will not exceed ten hours.</p><p><strong>47.3</strong> Subject to the roster provisions, 80 ordinary hours may be worked in any two (2) consecutive weeks, but not more than 50 ordinary hours may be worked in any one such week.</p><p><strong>47.4</strong> For all purposes the hourly rate is deemed to be the weekly rate prescribed by <a href="/eba/ebas/allied-health/wages/28-wages-and-wage-increases.html">clause 28</a> (Wages and Wage Increases) and set out in <a href="/eba/ebas/allied-health/appendices/2-wage-rates.html">Appendix 2</a> divided by 38. See subclause 48.1 for how this operates where an averaging system is used.</p><p><strong>47.5</strong> A paid leave day will be identical to a worked day. Nothing in this subclause 47.5 prevents an Employee from cashing out annual leave in accordance with subclause 60.4 (Part-time Employees – cashing out of annual leave where contracted EFT fraction has reduced).</p><p><strong>47.6</strong> Employees will be rostered so as to provide for four (4) days free from ordinary duty per fortnight including not less than two (2) consecutive days, unless otherwise mutually agreed between the Employer and the Employee. Any ADO (where relevant) is in addition to the days free from ordinary duty referred to in this subclause 47.6.</p><p><strong>47.7</strong> Where the Employer requires an Employee to sleepover on the Employer&#39;s premises, this sleepover will be counted as time worked and paid:</p><p><strong>(a)</strong> at the Employee’s ordinary rate of pay plus the applicable shift work allowance (per <a href="/eba/ebas/allied-health/allowances/38-shift-work-allowance.html">clause 38</a>) where this is part of the Employee’s ordinary hours of work; or</p><p><strong>(b)</strong> at overtime rates where this is not part of the Employee’s ordinary hours of work.</p><p><strong>47.8</strong> 10-hour break between ordinary shifts</p><p><strong>(a)</strong> Subject to subclause 47.8(b), the Employer will provide an Employee with at least ten consecutive (10) hours off duty between successive ordinary shifts, which will</p><p>be reflected in any rosters that apply to the Employee. See also <a href="/eba/ebas/allied-health/hours-of-work/55-rest-period-after-overtime-recall-ten-hour-break.html">clause 55</a> for the periods off duty involving overtime.</p><p><strong>(b)</strong> Where for urgent operational issues there is not at least (10) ten consecutive hours off duty between successive ordinary shifts as required at subclause 47.8(a), the Employee shall either:</p><p><strong>(i)</strong> be released from duty without loss of pay until the Employee has had 10 consecutive hours off duty; or</p><p><strong>(ii)</strong> be paid at the rate of double time until released from duty for such rest period, where the employee is required to work without a 10 hour break on the instructions of the Employer.</p><p><strong>47.9</strong> Broken Shifts An Employee will not work broken shifts (that is, their work is to be continuous excluding meal and other breaks), unless the Employee:</p><p><strong>(a)</strong> agrees to work broken shifts under a flexible working arrangement (<a href="/eba/ebas/allied-health/workplace-rights/96-flexible-working-arrangements.html">clause 96</a> and section 65 of the Act); or</p><p><strong>(b)</strong> agrees to work broken shifts under an individual flexibility agreement (<a href="/eba/ebas/allied-health/preliminary/12-individual-flexibility-arrangement.html">clause 12</a>). Right to Disco nnect</p><p>Plain language terms: ordinary hours.</p>',27)])])}const c=r(s,[["render",n]]);export{f as __pageData,c as default};
